,'4169750 07','429998004','230285003'\r",",'56267009','230286002','230287006','230270009','230273006','90099008','230280008','86188000','13092008','21921000119103','429458009','442344002','792004'\r",",'713060000','425390006'\r","--Dementia SNOMED codes Page 15 of Dementia Care Pathway Appendices\r",",'713844000','191475009','80098002','312991009','135811000119107','13 5 8110 0 0119107','42769004','191519005','281004','191493005','111480006','1114 8 0 0 0 6'\r",",'32875003','59651006','278857002','230269008','79341000119107','12348006','421023003','713488003','191452002','65096006','31081000119101','191455000'\r",",'1089501000000102','10532003','191454001','230267005','230268000','230265002'\r","--Dementia SNOMED codes Page 16 of Dementia Care Pathway Appendices\r",",'230266001','191451009','1914510 09','22381000119105','230288001','191458003','191459006','191463004','191464005','191465006','191466007','279982005','6475002'\r",",'66108005'\r","\t\r","--Dementia Read code v2 on Page 17 of Dementia Care Pathway Appendices\r",",'E00..%','E0 0..%','Eu01.%','Eu 01.%','Eu02.%','Eu 02.%','E012.%','Eu00.%','Eu 0 0.%','F110.%','A411.%','A 411.%','E02y1','E041.','E0 41.','Eu041','Eu 0 41'\r",",'F111.','F112.','F116.','F118.','F21y2','A410.','A 410.'\r","\t\r","--Dementia CTV3 code on Page 17 of Dementia Care Pathway Appendices\r","--F110.%, Eu02.%,'E02y1' are in this list but are mentioned in the read code v2 list\r",",'XE1Xr%','X002w%','XE1Xs','Xa0sE'\r","\r","--MCI codes\r",",'F06.7','F067' --ICD10 codes on Page 13 of Dementia Care Pathway Appendices\r",",'386805003' --SNOMED Code on Page 16 of Dementia Care Pathway Appendices\r",",'28E0.' --Read code v2 on Page 17 of Dementia Care Pathway Appendices\r",",'Xaagi' --CTV3 code on Page 17 of Dementia Care Pathway Appendices\r",")\r","\r","OR p.PrimDiag LIKE 'F03%')\r","\r","\r","---- Combine with secondary diagnoses \r","INSERT INTO [MHDInternal].Temp_DEM_MAS_Diag\r","\r"," SELECT \r","\tp.Der_Person_ID\r","\t,p.UniqServReqID\r","\t,p.RecordNumber\r","\t,p.UniqMonthID\r","\t,'SECONDARY' AS DiagType \r","\t,p.SecDiag AS [Diagnosis]\r","\t,p.CodedDiagTimestampDatetime\r","\t,CASE WHEN SecDiag IN ('F06.7','F067','386805003','28E0.','Xaagi') THEN 'MCI' ELSE 'Dementia' END AS 'Diagnosis Area'\r"," \r"," FROM MESH_MHSDS.MHS605SecDiag p\r"," INNER JOIN MESH_MHSDS.MHSDS_SubmissionFlags f ON p.NHSEUniqSubmissionID = f.NHSEUniqSubmissionID AND f.Der_IsLatest = 'Y' \r","\r"," WHERE \r","(p.SecDiag IN\r","\r","(--Dementia ICD10 codes Page 13 of Dementia Care Pathway Appendices\r","'F00.0','F00.1','F00.2','F00.9','F01.0','F01.1','F01.2','F01.3','F01.8','F01.9','F02.0','F02.1','F02.2','F02.3','F02.4','F02.8','F03','F05.1'\r",",'F000','F001','F002','F009','F010','F011','F012','F013','F018','F019','F020','F021','F022','F023','F024','F028','F051'\r","\r","--This Dagger code is included as it is required in combination with F02.8 to identify Lewy body disease. \r","--We are unable to filter MHSDS for those with both F02.8 AND G31.8 so have to filter for those with either F02.8 or G31.8\r",",'G318','G31.8'\r","\r","--Dementia SNOMED codes Page 14 of Dementia Care Pathway Appendices\r",",'52448006','15662003','191449005','191457008','191461002','231438001','268612007','45864009','26929004','416780008','416975007','4169750 07','429998004','230285003'\r",",'56267009','230286002','230287006','230270009','230273006','90099008','230280008','86188000','13092008','21921000119103','429458009','442344002','792004'\r",",'713060000','425390006'\r","--Dementia SNOMED codes Page 15 of Dementia Care Pathway Appendices\r",",'713844000','191475009','80098002','312991009','135811000119107','13 5 8110 0 0119107','42769004','191519005','281004','191493005','111480006','1114 8 0 0 0 6'\r",",'32875003','59651006','278857002','230269008','79341000119107','12348006','421023003','713488003','191452002','65096006','31081000119101','191455000'\r",",'1089501000000102','10532003','191454001','230267005','230268000','230265002'\r","--Dementia SNOMED codes Page 16 of Dementia Care Pathway Appendices\r",",'230266001','191451009','1914510 09','22381000119105','230288001','191458003','191459006','191463004','191464005','191465006','191466007','279982005','6475002'\r",",'66108005'\r","\t\r","--Dementia Read code v2 on Page 17 of Dementia Care Pathway Appendices\r",",'E00..%','E0 0..%','Eu01.%','Eu 01.%','Eu02.%','Eu 02.%','E012.%','Eu00.%','Eu 0 0.%','F110.%','A411.%','A 411.%','E02y1','E041.','E0 41.','Eu041','Eu 0 41'\r",",'F111.','F112.','F116.','F118.','F21y2','A410.','A 410.'\r","\t\r","--Dementia CTV3 code on Page 17 of Dementia Care Pathway Appendices\r","--F110.%, Eu02.%,'E02y1' are in this list but are mentioned in the read code v2 list\r",",'XE1Xr%','X002w%','XE1Xs','Xa0sE'\r","\r","--MCI codes\r",",'F06.7','F067' --ICD10 codes on Page 13 of Dementia Care Pathway Appendices\r",",'386805003' --SNOMED Code on Page 16 of Dementia Care Pathway Appendices\r",",'28E0.' --Read code v2 on Page 17 of Dementia Care Pathway Appendices\r",",'Xaagi' --CTV3 code on Page 17 of Dementia Care Pathway Appendices\r",")\r","\r","OR p.SecDiag LIKE 'F03%')\r","\r","\r","\r","/* \u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\r","RANK DEMENTIA DIAGNOSES WITHIN REFERRALS \r","\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e*/ \r","\r","IF OBJECT_ID ('[MHDInternal].[Temp_DEM_MAS_DiagRank]') IS NOT NULL \r","DROP TABLE [MHDInternal].Temp_DEM_MAS_DiagRank\r","\r"," SELECT \r","\tUniqServReqID\r","\t,Der_Person_ID\r","\t,CodedDiagTimestampDatetime\r","\t,UniqMonthID\r","\t,Diagnosis\r","\t,[Diagnosis Area]\r","\t,ROW_NUMBER() OVER(PARTITION BY [UniqServReqID],[Der_Person_ID] ORDER BY CodedDiagTimestampDatetime ASC, [Diagnosis Area] DESC ) AS RowIDEarliest\t--There are instances of more than one primary diagnosis with the same timestamp. In this case MCI is used over Dementia as the latest diagnosis is ordered alphabetically.\r","\t,ROW_NUMBER() OVER(PARTITION BY [UniqServReqID],[Der_Person_ID] ORDER BY CodedDiagTimestampDatetime DESC, [Diagnosis Area] ASC) AS RowIDLatest\t\t--There are instances of more than one primary diagnosis with the same timestamp. In this case Dementia is used over MCI as ordered alphabetically.\r","\r","INTO [MHDInternal].Temp_DEM_MAS_DiagRank\r","\r","FROM [MHDInternal].Temp_DEM_MAS_Diag\r","\r","\r","\r","\r"," /* \u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\r","GET ALL DEMENTIA REFERRALS \r","\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e*/ \r","\r"," IF OBJECT_ID ('[MHDInternal].[Temp_DEM_MAS_Ref]') IS NOT NULL \r"," DROP TABLE [MHDInternal].Temp_DEM_MAS_Ref\r","\r"," SELECT \r","\tr.UniqServReqID\r","\t,r.Person_ID\r","\t,r.ReportingPeriodStartDate\r","\t,r.ReportingPeriodEndDate\r","\t,r.RecordNumber\r","\t,r.ServTeamTypeRefToMH\r","\t,r.PrimReasonReferralMH\r","\t,d.CodedDiagTimestampDatetime AS DiagDate_first \r","\t,d.Diagnosis AS Diagnosis_first\r","\t,d.[Diagnosis Area] AS DiagnosisArea_first\r","\t,r.ReferralRequestReceivedDate\r","\t,r.ServDischDate\r","\t,r.OrgIDProv\r","\t,r.Der_SubICBCode -- GP derived commissioner \r","\t,r.AgeServReferRecDate\r","\t,r.EthnicCategory\r","\t,r.Gender\r","\r","INTO [MHDInternal].Temp_DEM_MAS_Ref\r","\t\r","FROM MHDInternal.PreProc_Referral r \r","\r","LEFT JOIN MHDInternal.Temp_DEM_MAS_DiagRank d ON r.UniqServReqID = d.UniqServReqID AND r.Person_ID = d.Der_Person_ID AND d.RowIDEarliest = 1 AND d.CodedDiagTimestampDatetime \u003c= r.ReportingPeriodEndDate\r","\r","WHERE  (r.UniqMonthID BETWEEN @RPSTART AND @RPEND)\r","AND\r","\t(r.ServTeamTypeRefToMH = 'A17' -- Memory Service/Clinic\r","\tOR r.PrimReasonReferralMH = '08' --- OBD \r","\tOR d.CodedDiagTimestampDatetime \u003c= r.ReportingPeriodEndDate -- Dementia/MCI diagnosis)\r","\t)\r","\r","\r","\r","/* \u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\r","CALCULATE DEMENTIA REFERRAL DIMENSIONS \r","\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e*/ \r","\r","IF OBJECT_ID ('[MHDInternal].[Temp_DEM_MAS_Dim]') IS NOT NULL \r","DROP TABLE [MHDInternal].Temp_DEM_MAS_Dim\r","\r","SELECT \r","\tr.UniqServReqID\r","\t,r.Person_ID\r","\t,r.ReportingPeriodStartDate\r","\t,r.ReportingPeriodEndDate\r","\t,r.RecordNumber\r","\t,r.ServTeamTypeRefToMH\r","\t,COALESCE(t.Main_Description, 'Missing/invalid') AS TeamType \r","\t,r.PrimReasonReferralMH\r","\t,ISNULL(rr.Main_Description, 'Missing/invalid') AS PrimReason\r","\t,r.DiagDate_first\r","\t,r.Diagnosis_first \r","\t,r.DiagnosisArea_first \r","\t,r.ReferralRequestReceivedDate\r","\t,r.ServDischDate\r","\t,r.OrgIDProv \r","\t,p.Organisation_Name AS Provider_Name\r","\t,COALESCE(cc.New_Code,r.Der_SubICBCode, 'Missing/Invalid') AS SubICBCode \r","\t,COALESCE(c.Organisation_Name,'Missing/Invalid') AS Sub_ICB_Name\r","\t,COALESCE(c.STP_Code,'Missing/Invalid') AS ICB_Code\r","\t,COALESCE(c.STP_Name,'Missing/Invalid') AS ICB_Name\r","\t,COALESCE(c.Region_Code,'Missing/Invalid') AS Comm_Region_Code\r","\t,COALESCE(c.Region_Name,'Missing/Invalid') AS Comm_Region_Name \r","\t,p.Region_Code AS Prov_Region_Code \r","\t,p.Region_Name AS Prov_Region_Name \r","\t,r.AgeServReferRecDate\r","\t,CASE WHEN AgeServReferRecDate \u003c 65 THEN 'Under65'\r","\t\tWHEN AgeServReferRecDate BETWEEN 65 AND 74 THEN '65to74'\r","\t\tWHEN AgeServReferRecDate BETWEEN 75 AND 84 THEN '75to84'\r","\t\tWHEN AgeServReferRecDate \u003e= 85 THEN '85+' \r","\t\tELSE 'Unknown/Not Stated' \r","\tEND AS AgeGroup\r","\t,CASE \r","\t\tWHEN e.Category IS NULL THEN  'Missing / invalid'\r","\t\tWHEN e.Category = '' THEN 'Missing / invalid'\r","\t\tELSE CONCAT(e.[Category],' - ',e.[Main_Description_60_Chars])\r","\tEND AS EthnicCategory\r","\t,COALESCE(g.Main_Description, 'Missing / invalid') AS Gender\r","\r","INTO [MHDInternal].Temp_DEM_MAS_Dim\r","\r","FROM [MHDInternal].Temp_DEM_MAS_Ref r \r","\r","LEFT JOIN Reporting_UKHD_ODS.Provider_Hierarchies p ON r.OrgIDProv = p.Organisation_Code\r","LEFT JOIN Internal_Reference.ComCodeChanges cc ON r.Der_SubICBCode = cc.Org_Code\r","LEFT JOIN Reporting_UKHD_ODS.Commissioner_Hierarchies c ON COALESCE(cc.New_Code,r.Der_SubICBCode) = c.Organisation_Code\r","LEFT JOIN UKHD_Data_Dictionary.Service_Or_Team_Type_For_Mental_Health_SCD t ON r.ServTeamTypeRefToMH = t.Main_Code_Text COLLATE DATABASE_DEFAULT AND t.Effective_To IS NULL AND t.Valid_To IS NULL\r","LEFT JOIN UKHD_Data_Dictionary.Reason_For_Referral_To_Mental_Health_SCD rr ON r.PrimReasonReferralMH = rr.Main_Code_Text COLLATE DATABASE_DEFAULT AND rr.Effective_To IS NULL AND rr.Valid_To IS NULL\r","LEFT JOIN UKHD_Data_Dictionary.Ethnic_Category_Code_SCD_1 e ON r.EthnicCategory = e.[Main_Code_Text] COLLATE DATABASE_DEFAULT AND e.Is_Latest = 1\r","LEFT JOIN UKHD_Data_Dictionary.Person_Gender_Code_SCD g ON r.Gender = g.Main_Code_text COLLATE DATABASE_DEFAULT AND g.Effective_To IS NULL AND g.Valid_To IS NULL\r","\r","\r","/* \u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\r","GET FIRST CARE CONTACT FOR DEMENTIA REFERRALS \r","\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e*/ \r","\r","IF OBJECT_ID ('MHDInternal.Temp_DEM_MAS_FirstCont') IS NOT NULL\r","DROP TABLE MHDInternal.Temp_DEM_MAS_FirstCont\r","\r","SELECT\r","\tr.ReportingPeriodEndDate,\r","\tr.RecordNumber,\r","\tr.UniqServReqID,\r","\r","\t-- cumulative activity\r","\tMAX(a.Der_ContactDate) AS Der_LastContact,\r","\tMIN(a.Der_ContactDate) AS Der_FirstContactDate,\r","\tSUM(a.Der_Contact) AS Der_CumulativeContacts\r","\r","INTO MHDInternal.Temp_DEM_MAS_FirstCont\r","\r","FROM MHDInternal.Temp_DEM_MAS_Dim r\r","\r","LEFT JOIN MHDInternal.PreProc_Activity a ON a.Person_ID = r.Person_ID AND r.UniqServReqID = a.UniqServReqID \r","\tAND a.ReportingPeriodEndDate \u003c= r.ReportingPeriodEndDate \r","\r","WHERE a.Der_DirectContact = 1\r","\r","GROUP BY r.RecordNumber, r.ReportingPeriodEndDate, r.UniqServReqID\r","\r","\r","/* \u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\r","GET EARLIEST CARE PLAN CREATED FOR DEMENTIA REFERRALS \r","\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e*/ \r","\r","IF OBJECT_ID ('[MHDInternal].[Temp_DEM_MAS_CarePlan]') IS NOT NULL \r","DROP TABLE [MHDInternal].Temp_DEM_MAS_CarePlan\r","\r","SELECT \r","\tr.UniqServReqID\r","\t,r.Person_ID\r","\t,r.ReportingPeriodEndDate\r","\t,r.RecordNumber \r","\t,MIN(cp.CarePlanCreatDate) AS First_CarePlan\r","\r","INTO [MHDInternal].Temp_DEM_MAS_CarePlan\r","\r","FROM [MHDInternal].Temp_DEM_MAS_Dim r  \r","\r","INNER JOIN MESH_MHSDS.MHS008CarePlanType cp ON r.Person_ID = cp.Der_Person_ID AND r.RecordNumber = cp.RecordNumber \r","\r","GROUP BY r.UniqServReqID, r.Person_ID, r.ReportingPeriodEndDate, r.RecordNumber \r","ORDER BY 1,3\r","\r","\r","\r","/* \u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\r","CALCULATE MEASURES \r","\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e*/ \r","\r","IF OBJECT_ID ('[MHDInternal].[Temp_DEM_MAS_Master]') IS NOT NULL \r","DROP TABLE [MHDInternal].Temp_DEM_MAS_Master\r","\r","SELECT \r","\td.UniqServReqID\r","\t,d.Person_ID\r","\t,d.ReportingPeriodStartDate\r","\t,d.ReportingPeriodEndDate\r","\t,d.RecordNumber\r","\t,d.ServTeamTypeRefToMH\r","\t,d.TeamType \r","\t,d.PrimReasonReferralMH\r","\t,d.PrimReason\r","\t,d.DiagDate_first\r","\t,d.Diagnosis_first \r","\t,d.DiagnosisArea_first \r","\t,d.ReferralRequestReceivedDate\r","\t,d.ServDischDate\r","\t,f.Der_FirstContactDate\r","\t,f.Der_CumulativeContacts\r","\t,d.OrgIDProv \r","\t,d.Provider_Name\r","\t,d.SubICBCode \r","\t,d.Sub_ICB_Name\r","\t,d.ICB_Code\r","\t,d.ICB_Name\r","\t,d.Comm_Region_Code\r","\t,d.Comm_Region_Name \r","\t,d.Prov_Region_Code\r","\t,d.Prov_Region_Name\r","\t,d.AgeServReferRecDate\r","\t,d.AgeGroup\r","\t,d.EthnicCategory\r","\t,d.Gender\r","\t--- Caseload measures \r","\t,CASE WHEN d.ReferralRequestReceivedDate BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate THEN 1 ELSE 0 END AS [New referrals] -- new referrals in RP\r","\t,CASE WHEN d.ServDischDate BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate THEN 1 ELSE 0 END AS [Discharged referrals] -- referrals discharged in RP \r","\t,CASE WHEN d.ServDischDate IS NULL OR d.ServDischDate \u003e d.ReportingPeriodEndDate THEN 1 ELSE 0 END AS [Open referrals] --- refs open at RP end \r","\t,CASE WHEN (d.ServDischDate IS NULL OR d.ServDischDate \u003e d.ReportingPeriodEndDate) AND (f.Der_FirstContactDate IS NULL OR f.Der_FirstContactDate \u003e d.ReportingPeriodEndDate) THEN 1 ELSE 0 END AS [Open waiting for contact] -- open refs waiting for contact\r","\t,CASE WHEN (d.ServDischDate IS NULL OR d.ServDischDate \u003e d.ReportingPeriodEndDate) AND f.Der_LastContact IS NOT NULL THEN 1 ELSE 0 END AS [Caseload] \r","\t,CASE WHEN (d.ServDischDate IS NULL OR d.ServDischDate \u003e d.ReportingPeriodEndDate) AND (c.First_CarePlan \u003c= d.ReportingPeriodEndDate) THEN 1 ELSE 0 END AS [Open with Care Plan] -- open refs with a Care Plan \r","\t--- Time to first contact \r","\t,CASE WHEN f.Der_FirstContactDate BETWEEN d.ReportingPeriodStartDate and d.ReportingPeriodEndDate THEN 1 ELSE 0 END AS [First contact in RP] -- having first contact in month \r","\t,CASE WHEN f.Der_FirstContactDate BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate THEN DATEDIFF(DD, ReferralRequestReceivedDate, Der_FirstContactDate) END AS [Time to 1st contact] -- time from ref to 1st contact, where 1st contact in RP\r","\t,CASE WHEN f.Der_FirstContactDate BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate AND DATEDIFF(DD, ReferralRequestReceivedDate, Der_FirstContactDate) \u003c (6*7) THEN 1 ELSE 0 END AS [Time to 1st contact - under 6 weeks] -- time from ref to 1st contact, where 1st contact in RP\r","\t,CASE WHEN f.Der_FirstContactDate BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate AND DATEDIFF(DD, ReferralRequestReceivedDate, Der_FirstContactDate) BETWEEN (6*7) AND (18*7) THEN 1 ELSE 0 END AS [Time to 1st contact - 6-18 weeks] -- time from ref to 1st contact, where 1st contact in RP\r","\t,CASE WHEN f.Der_FirstContactDate BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate AND DATEDIFF(DD, ReferralRequestReceivedDate, Der_FirstContactDate) \u003e (18*7) THEN 1 ELSE 0 END AS [Time to 1st contact - over 18 weeks] -- time from ref to 1st contact, where 1st contact in RP\r","\t--- Time to first diagnosis \r","\t,CASE WHEN d.DiagDate_first BETWEEN d.ReportingPeriodStartDate and d.ReportingPeriodEndDate THEN 1 ELSE 0 END AS [First diag in RP] -- having first contact in month \r","\t,CASE WHEN d.DiagDate_first BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate THEN DATEDIFF(DD, ReferralRequestReceivedDate, DiagDate_first) END AS [Time to 1st diag] -- time from ref to 1st contact, where 1st contact in RP\r","\t,CASE WHEN d.DiagDate_first BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate AND DATEDIFF(DD, ReferralRequestReceivedDate, DiagDate_first) \u003c (6*7) THEN 1 ELSE 0 END AS [Time to 1st diag - under 6 weeks] -- time from ref to 1st contact, where 1st contact in RP\r","\t,CASE WHEN d.DiagDate_first BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate AND DATEDIFF(DD, ReferralRequestReceivedDate, DiagDate_first) BETWEEN (6*7) AND (18*7) THEN 1 ELSE 0 END AS [Time to 1st diag - 6-18 weeks] -- time from ref to 1st contact, where 1st contact in RP\r","\t,CASE WHEN d.DiagDate_first BETWEEN d.ReportingPeriodStartDate AND d.ReportingPeriodEndDate AND DATEDIFF(DD, ReferralRequestReceivedDate, DiagDate_first) \u003e (18*7) THEN 1 ELSE 0 END AS [Time to 1st diag - over 18 weeks] -- time from ref to 1st contact, where 1st contact in RP\r","\r","\t,CASE WHEN DiagDate_first \u003e= ReferralRequestReceivedDate THEN 'Diagnosis After Referral' WHEN DiagDate_first\u003cReferralRequestReceivedDate THEN 'Diagnosis Before Referral' ELSE 'No Diagnosis' END AS RefToEarliestDiagOrder\r","\r","INTO [MHDInternal].Temp_DEM_MAS_Master\r","\r","FROM MHDInternal.Temp_DEM_MAS_Dim d \r","\r","LEFT JOIN [MHDInternal].Temp_DEM_MAS_FirstCont f ON d.UniqServReqID = f.UniqServReqID AND d.RecordNumber = f.RecordNumber \r","LEFT JOIN [MHDInternal].Temp_DEM_MAS_CarePlan c ON d.UniqServReqID = c.UniqServReqID AND d.RecordNumber = c.RecordNumber \r","\r","\r","\r","\r","/* \u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\r","AGGREGATE MAIN ACTIVITY MESAURES \r","\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e*/ \r","\r","IF OBJECT_ID ('[MHDInternal].Temp_DEM_MAS_AggMain') IS NOT NULL \r","DROP TABLE [MHDInternal].Temp_DEM_MAS_AggMain\r","\r","SELECT \r","\t'Main Dashboard' AS Section\r","\t,ReportingPeriodEndDate\r","\t,OrgIDProv AS [Provider Code] \r","\t,Provider_Name AS [Provider Name] \r","\t,SubICBCode AS [SubICB Code]\r","\t,Sub_ICB_Name AS [SubICB Name]\r","\t,m.ICB_Code AS [ICB Code]\r","\t,ICB_Name AS [ICB Name]\r","\t,Comm_Region_Code AS [Region Code]\r","\t,Comm_Region_Name AS [Region Name] \t\r","\t,TeamType AS [Team Type]\r","\t,PrimReason AS [Primary reason for referral]\r","\t,ISNULL(DiagnosisArea_first,'None') AS [Diagnosis] \r","\t,SUM([New referrals]) AS [New referrals]\r","\t,SUM([Discharged referrals]) AS [Discharged referrals]\r","\t,SUM([Open referrals]) AS [Open referrals]\r","\t,SUM([Open waiting for contact]) AS [Open waiting for contact]\r","\t,SUM(Caseload) AS Caseload\r","\t,SUM([Open with Care Plan]) AS [Open with Care Plan]\r","\r","\t,SUM([First contact in RP]) AS [First contact in RP]\r","\t,SUM([Time to 1st contact]) AS [Time to 1st contact] -- numerator for mean time to 1st contact \r","\t,SUM([Time to 1st contact - under 6 weeks]) AS [Time to 1st contact - under 6 weeks]\r","\t,SUM([Time to 1st contact - 6-18 weeks]) AS [Time to 1st contact - 6-18 weeks]\r","\t,SUM([Time to 1st contact - over 18 weeks]) AS [Time to 1st contact - over 18 weeks]\r","\t\r","\t,SUM([First diag in RP]) AS [First diag in RP]\r","\t,SUM([Time to 1st diag]) AS [Time to 1st diag] --- numerator for mean time to 1st diag \r","\t,SUM([Time to 1st diag - under 6 weeks]) AS [Time to 1st diag - under 6 weeks]\r","\t,SUM([Time to 1st diag - 6-18 weeks]) AS [Time to 1st diag - 6-18 weeks]\r","\t,SUM([Time to 1st diag - over 18 weeks]) AS [Time to 1st diag - over 18 weeks]\r","\r","\t-- Duplicate measures for Tableau denominators \r","\t,SUM([Open referrals]) AS [Open referrals2]\r","\t,SUM([First contact in RP]) AS [First contact in RP2]\r","\t,SUM([First diag in RP]) AS [First diag in RP2]\r","\r","INTO [MHDInternal].Temp_DEM_MAS_AggMain\r","\r","FROM [MHDInternal].Temp_DEM_MAS_Master m \r","\r","GROUP BY ReportingPeriodEndDate, OrgIDProv , Provider_Name ,SubICBCode ,Sub_ICB_Name \r","\t,ICB_Code,ICB_Name,Comm_Region_Code,Comm_Region_Name ,TeamType ,PrimReason ,DiagnosisArea_first\r","\r","\r","\r","\r","/*\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\r","UNPIVOT AND CREATE ACTIVITY EXTRACT\r","\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e\u003e*/\r","\r","IF OBJECT_ID ('MHDInternal.[Dashboard_Dem_MAS]') IS NOT NULL\r","DROP TABLE MHDInternal.[Dashboard_Dem_MAS]\r","\r","SELECT\r","\tReportingPeriodEndDate,\r","\t[Provider code],\r","\t[Provider name],\r","\t[SubICB Code],\r","\t[SubICB Name],\r","\t[ICB Code],\r","\t[ICB Name],\r","\t[Region code],\r","\t[Region name],\r","\tDiagnosis,\r","\t[Primary reason for referral],\r","\t[Team type],\r","\tMeasureName,\r","\tMeasureValue,\r","\tCASE \r","\t\tWHEN MeasureName IN ('Open waiting for contact','Caseload','Open with Care Plan') THEN [Open referrals2]\r","\t\tWHEN MeasureName = 'Time to 1st contact' THEN [First contact in RP2] \r","\t\tWHEN MeasureName IN ('Time to 1st contact - under 6 weeks','Time to 1st contact - 6-18 weeks','Time to 1st contact - over 18 weeks') THEN [First contact in RP2]\r","\t\tWHEN MeasureName = 'Time to 1st diag' THEN [First diag in RP2] \r","\t\tWHEN MeasureName IN ('Time to 1st diag - under 6 weeks','Time to 1st diag - 6-18 weeks','Time to 1st diag - over 18 weeks') THEN [First diag in RP2]\r","\tEND\tAS Denominator\r","\r","INTO [MHDInternal].[Dashboard_Dem_MAS]\r","\r","FROM MHDInternal.Temp_DEM_MAS_AggMain \r","\r","UNPIVOT (MeasureValue FOR MeasureName IN \r","\t([New referrals],[Discharged referrals], [Open referrals], [Open waiting for contact], [Caseload], [Open with Care Plan],\r","\t[First contact in RP], [Time to 1st contact], [Time to 1st contact - under 6 weeks], [Time to 1st contact - 6-18 weeks], [Time to 1st contact - over 18 weeks],\r","\t[First diag in RP], [Time to 1st diag], [Time to 1st diag - under 6 weeks], [Time to 1st diag - 6-18 weeks], [Time to 1st diag - over 18 weeks]\r","\t))u \r","\r","\r","\r","\r","--- DROP TEMPORARY TABLES \r","DROP TABLE [MHDInternal].Temp_DEM_MAS_Diag\r","DROP TABLE MHDInternal.Temp_DEM_MAS_DiagRank\r","DROP TABLE MHDInternal.Temp_DEM_MAS_Ref\r","DROP TABLE MHDInternal.Temp_DEM_MAS_Dim\r","DROP TABLE MHDInternal.Temp_DEM_MAS_FirstCont\r","DROP TABLE MHDInternal.Temp_DEM_MAS_CarePlan \r","DROP TABLE MHDInternal.Temp_DEM_MAS_Master\r","DROP TABLE MHDInternal.Temp_DEM_MAS_AggMain \r"],"stylingDirectives":null,"colorizedLines":["\u003cspan class=\"pl-c\"\u003e\u003cspan class=\"pl-c\"\u003e/*\u003c/span\u003e \u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u003c/span\u003e","\u003cspan class=\"pl-c\"\u003eMAS DASHBOARD REBUILD \u003c/span\u003e","\u003cspan class=\"pl-c\"\u003e\u003c/span\u003e","\u003cspan class=\"pl-c\"\u003eCREATED 13 AUGUST 2024 \u003c/span\u003e","\u003cspan class=\"pl-c\"\u003e\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u